import openai

client = openai.OpenAI()

# Zero-shot classification
zero_shot = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[
        {"role": "user", "content": "Classify the sentiment of this review as POSITIVE, NEGATIVE, or NEUTRAL:\n'The battery life is amazing but the screen is too dim.'"}
    ]
)
print("Zero-shot:", zero_shot.choices[0].message.content)

# Few-shot classification — examples teach the pattern
few_shot = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[
        {
            "role": "system",
            "content": "Classify customer reviews. Output JSON with 'sentiment' and 'key_points' fields."
        },
        {
            "role": "user",
            "content": "Review: 'Fast shipping, product exactly as described. Will buy again.'"
        },
        {
            "role": "assistant",
            "content": '{"sentiment": "POSITIVE", "key_points": ["shipping speed", "product accuracy", "repeat purchase intent"]}'
        },
        {
            "role": "user",
            "content": "Review: 'Arrived broken. Customer service was unhelpful. Complete waste of money.'"
        },
        {
            "role": "assistant",
            "content": '{"sentiment": "NEGATIVE", "key_points": ["product damage", "poor customer service", "value dissatisfaction"]}'
        },
        {
            "role": "user",
            "content": "Review: 'The battery life is amazing but the screen is too dim.'"
        }
    ]
)
print("Few-shot:", few_shot.choices[0].message.content)
# Consistent JSON output with structured key_points
