import openai

client = openai.OpenAI()

# Without CoT — model jumps to answer
direct = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[
        {"role": "user", "content": "A store has 3 shelves with 8 items each. They sell 5 items per hour for 4 hours, then restock with 20 items. How many items are left?"}
    ]
)
print("Direct:", direct.choices[0].message.content)  # May be wrong

# With Chain-of-Thought — step-by-step reasoning
cot = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[
        {
            "role": "system",
            "content": "Solve problems step by step. Show your reasoning clearly before giving the final answer. Format: Step 1: ..., Step 2: ..., ..., Answer: ..."
        },
        {
            "role": "user",
            "content": "A store has 3 shelves with 8 items each. They sell 5 items per hour for 4 hours, then restock with 20 items. How many items are left?"
        }
    ]
)
print("\nCoT:", cot.choices[0].message.content)
# Step 1: 3 × 8 = 24 initial items
# Step 2: 5 × 4 = 20 items sold
# Step 3: 24 - 20 = 4 remaining
# Step 4: 4 + 20 = 24 after restock
# Answer: 24 items

# Structured CoT for code debugging
debug_cot = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[
        {
            "role": "system",
            "content": "Debug code by thinking step by step:\n1. Read the code and identify what it's supposed to do\n2. Trace execution with sample input\n3. Find where behavior diverges from expectation\n4. Propose fix with explanation"
        },
        {
            "role": "user",
            "content": "This function should return the sum of even numbers but returns wrong results:\n```python\ndef sum_even(numbers):\n    return sum(n for n in numbers if n % 2 == 1)\n```"
        }
    ]
)
print("\nDebug:", debug_cot.choices[0].message.content)
